import org.springframework.context.annotation.*;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.provisioning.InMemoryUserDetailsManager;
 
@Configuration // Defining a Configuration Class that will be used by Spring to load the beans defined in this class java_52672_CredentialValidator_A01 our ApplicationContext, enabling Autowiring of all necessary classes within @Bean Annotations and also Enabling Dependency Injection for Beans using Constructor-Injected or Setter injection. 
@EnableWebSecurity // Enable security on your web application (Spring Security Filter Chain). This is a special kind of annotation that can be used at class level to enable all the features combined by other @Enable* annotations such as @ComponentScan, etc in one place and also it provides more fine-grained control.
public class SpringSecurityConfig extends WebSecurityConfigurerAdapter { // Inheriting from a superclass for extending security configs with methods that allow configuration of HTTP Filter Chains (Filter chains are filters within the Security framework). 
     @Override    public void configure(AuthenticationManagerBuilder auth) throws Exception{   // This method is used to specify in-memory authentication. It’ll use InMemoryUserDetailsService and passwordEncoder as data source for database users with their hashed versions of encrypted (bCrypt encoded), role authorities, account expired status etc..
        BCryptPasswordEncoder bCryptPasswordEncoder = new BCryptPasswordEncoder();  //bcrypt encoding algorithm. The default strength is set to log(logN) * minlen and the cost parameter should be chosen such that a balance between computation time (and memory usage in particular, as these are related with each other).
        auth .userDetailsService(inMemoryUserDetailsManager()).passwordEncoder(bCryptPasswordEncoder);   //Setting up User details service. A custom user database is used to store the passwords of users and their roles/authorities – in-memory storage for this example, but you can use any data source that supports retrieving user credentials like JdbcUserDetailsService or LdapUserDetailsSource with Spring Security’s DaoAuthenticationProvider.
    }   //End Configure method: Auth management end points are defined here to handle login POST requests and return 200 OK status code (if success). AuthenticationManager can be configured via methods like addFilterBefore, etc which allows customization of the authentication process according your needs such as adding a specific filter or not.
} // End SpringSecurityConfig class definition with @Configuration annotation for Java-based configuration and use of WebSecurityConfigurerAdapter to enable security on an application using HTTP Filter Chains (and others).  The EnableWebSecurity is also used here in order the customizer functionalities that we have defined before it.